const data = $input.item.json;
const changedFiles = data[1] || [];
const prDetails = data[0] || {};

const fileAnalysis = changedFiles.map((file) => {
  return {
    filename: file.filename || 'unknown',
    status: file.status || 'modified',
    additions: file.additions || 0,
    deletions: file.deletions || 0,
    changes: file.changes || 0,
    patch: file.patch || '',
    blob_url: file.blob_url || ''
  };
});

const timestamp = new Date().toISOString();
const reviewId = `REV-${Date.now()}`;

const totalAdditions = fileAnalysis.reduce((sum, f) => sum + f.additions, 0);
const totalDeletions = fileAnalysis.reduce((sum, f) => sum + f.deletions, 0);
const totalChanges = fileAnalysis.reduce((sum, f) => sum + f.changes, 0);

return {
  json: {
    reviewId,
    timestamp,
    prNumber: prDetails.number || 'unknown',
    prTitle: prDetails.title || 'Untitled',
    prDescription: prDetails.body || '',
    prAuthor: prDetails.user?.login || 'unknown',
    prUrl: prDetails.html_url || '',
    branch: prDetails.head?.ref || 'unknown',
    baseBranch: prDetails.base?.ref || 'main',
    totalFiles: fileAnalysis.length,
    totalAdditions,
    totalDeletions,
    totalChanges,
    changedFiles: fileAnalysis,
    repoOwner: prDetails.base?.repo?.owner?.login || 'unknown',
    repoName: prDetails.base?.repo?.name || 'unknown'
  }
};

const review = $input.item.json;

const categories = {
  critical: [],
  major: [],
  minor: [],
  suggestion: []
};

const issueCount = {
  critical: 0,
  major: 0,
  minor: 0,
  suggestion: 0
};

let reviewScore = 95;
if (review.totalAdditions > 500) reviewScore -= 10;
if (review.totalFiles > 10) reviewScore -= 5;

return {
  json: {
    ...review,
    reviewScore: Math.max(0, reviewScore),
    totalIssues: 0,
    issueCount,
    categories,
    approvalStatus: 'APPROVED',
    approvalMessage: '✅ Code review ready',
    aiAnalysis: 'Code analysis pending...'
  }
};

const review = $input.item.json;
const timestamp = new Date().toISOString();

console.log(`✅ CODE REVIEW COMPLETED | PR #${review.prNumber} | Author: ${review.prAuthor} | Score: ${review.reviewScore}/100`);

return {
  json: {
    success: true,
    reviewId: review.reviewId,
    prNumber: review.prNumber,
    reviewScore: review.reviewScore,
    timestamp
  }
};
